const runDate = $('Compute Date').first().json.runDate;
const after  = `${runDate}T07:00:00Z`;
const before = DateTime.fromISO(runDate).plus({ days: 1 }).toFormat('yyyy-MM-dd') + 'T07:00:00Z';

const allNodes = [];
let cursor = null;
let hasNext = true;
let page = 0;

while (hasNext && page < 10) {
  page++;

  const afterArg = cursor ? `"${cursor}"` : 'null';
  const query = `query { visits(first: 30, after: ${afterArg}, filter: { startAt: { after: "${after}", before: "${before}" } }) { nodes { id startAt job { jobNumber } assignedUsers { nodes { name { full } } } property { address { street city province postalCode } } } pageInfo { hasNextPage endCursor } } }`;

  const response = await this.helpers.httpRequestWithAuthentication.call(
    this,
    'oAuth2Api',
    {
      method: 'POST',
      url: 'https://api.getjobber.com/api/graphql',
      headers: {
        'X-JOBBER-GRAPHQL-VERSION': '2025-04-16',
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({ query }),
      json: false,
    },
  );

  const parsed = typeof response === 'string' ? JSON.parse(response) : response;

  if (parsed.errors) {
    throw new Error('Jobber error: ' + JSON.stringify(parsed.errors));
  }

  const visits = parsed.data.visits;
  allNodes.push(...visits.nodes);

  hasNext = visits.pageInfo.hasNextPage;
  cursor  = visits.pageInfo.endCursor;

  // small breather so we never hammer the throttle bucket
  if (hasNext) {
    await new Promise(r => setTimeout(r, 300));
  }
}

return allNodes.map(n => ({ json: n }));
